                             f"{use_fp8_kv_cache=}, "
                             f"{use_fp8_qdq=}, "
                             f"{use_fp8_block_scales=}, "
                             f"{use_fp8_rowwise=}, "
                             f"{use_nvfp4=}, "
                             f"{use_w4a8_qserve=}, "
                             f"{use_w4a8_mxfp4_fp8=}, "
